import React, { useMemo } from 'react';
import { SearchInput } from '@linm-soft/common-components';
import { createContractSearchConfig } from './contractSearchConfig';

interface ContractSearchFieldProps {
  contractCode: string;
  customerName?: string;
  onSelect: (code: string, customerName: string) => void;
  onClear: () => void;
  disabled?: boolean;
  placeholder?: string;
}

/** SearchInput wrapper — lưu contractCode (string) theo registry field-control */
export const ContractSearchField: React.FC<ContractSearchFieldProps> = ({
  contractCode,
  customerName = '',
  onSelect,
  onClear,
  disabled,
  placeholder = 'Nhập mã hợp đồng...',
}) => {
  const config = useMemo(() => createContractSearchConfig(), []);

  return (
    <SearchInput
      config={config}
      value={contractCode}
      primaryDisplay={contractCode}
      secondaryDisplay={customerName}
      onChange={c => onSelect(c.code, c.customerName)}
      onClear={onClear}
      showLabel={false}
      placeholder={placeholder}
      disabled={disabled}
    />
  );
};
